"use client";

import { useEffect, useState } from "react";

import WelcomeMessage from "@/components/welcome-message";
import SearchSection from "@/components/search-section";
import FeaturedHotels from "@/components/featured-hotels";
import Highlights from "@/components/highlights";
import Reviews from "@/components/reviews";
import Articles from "@/components/articles";
import Gallery from "@/components/gallery";
import Contact from "@/components/contact";

export default function Page() {
  const [showWelcome, setShowWelcome] = useState(false);

  useEffect(() => {
    // Check if user has seen the popup before
    const hasSeen = localStorage.getItem("seen_welcome");

    if (!hasSeen) {
      setShowWelcome(true); // show popup
      localStorage.setItem("seen_welcome", "true"); // store preference
    }
  }, []);

  return (
    <div className="pt-28">

      {/* ONLY SHOW THIS IF NOT SEEN BEFORE */}
      {showWelcome && <WelcomeMessage onClose={() => setShowWelcome(false)} />}

      {/* Search Section */}
      <SearchSection />

      {/* Featured Hotels */}
      <div className="mt-12 px-6">
        <FeaturedHotels />
      </div>

      {/* Highlights */}
      <div className="mt-12 px-6">
        <Highlights />
      </div>

      {/* Reviews */}
      <div className="mt-12 px-6">
        <Reviews />
      </div>

      {/* Articles */}
      <div className="mt-12 px-6">
        <Articles />
      </div>

      {/* Gallery */}
      <div className="mt-12 px-6 pb-20">
        <Gallery />
      </div>
    </div>
  );
}
